class OrderProcessor {
  constructor(validator, repo, emailer) {
    this.validator = validator;
    this.repo = repo;
    this.emailer = emailer;
  }
  process(order) {
    this.validator.validate(order);
    this.repo.save(order);
    this.emailer.sendConfirmation(order.email);
  }
}
